            If None, defaults to count and average score per group

    Returns:
        Dictionary mapping group_value to aggregated statistics
        Example: {"tech": {"count": 5, "avg_score": 0.85, "max_score": 0.95}}
    """
    # Initialize dictionary to store aggregated results
    aggregated_data = defaultdict(lambda: {
        "count": 0,
        "sum_scores": 0.0,
        "max_score": float('-inf'),
        "min_score": float('inf'),
        "results": []
    })

    # Process each search result
    for result in search_results:
        # Extract group value from metadata
        metadata = result.metadata or {}
        group_value = metadata.get(group_by_field)

        # Handle missing group field values
        if group_value is None:
            group_value = "unknown"

        # Accumulate statistics for the group
        group_stats = aggregated_data[group_value]

        # Update count and sum of scores
        group_stats["count"] += 1
        group_stats["sum_scores"] += result.score

        # Update max and min scores
        if result.score > group_stats["max_score"]:
            group_stats["max_score"] = result.score
        if result.score < group_stats["min_score"]:
            group_stats["min_score"] = result.score

        # Store individual results for potential custom aggregation
        group_stats["results"].append(result)

