                        for result in stats["results"]:
                            if result.metadata and result.metadata.get(field_name) is not None:
                                data.append(result.metadata[field_name])

                    # Apply the aggregation function
                    if data:
                        group_result[field_name] = func(data)
                    else:
                        group_result[field_name] = None
                except Exception as e:
                    # Handle errors in custom aggregation
                    group_result[field_name] = f"Error: {str(e)}"

        final_results[group_value] = group_result

    return final_results

