from typing import List, Dict, Any, Optional
from leann.cli import LeannCLI
from leann.api import LeannBuilder, LeannSearcher
from pathlib import Path

def convert_cli_args_to_api_config(
    args_list: List[str],
    command_type: str = "build"
) -> Dict[str, Any]:
    """Convert CLI arguments to API configuration dictionary.

    Args:
        args_list: List of command line arguments
        command_type: Type of command ('build' or 'search')

    Returns:
        Dictionary containing API configuration extracted from CLI arguments
    """
    # Create LeannCLI instance to access argument parsers
    cli = LeannCLI()

    # Get the appropriate parser based on command type
    if command_type == "build":
        parser = cli.build_parser
    elif command_type == "search":
        parser = cli.search_parser
    else:
        raise ValueError(f"Unsupported command type: {command_type}. Must be 'build' or 'search'")

    # Parse the arguments using the selected parser
    args = parser.parse_args(args_list)

    # Initialize configuration dictionary with basic information
    config = {
        "command_type": command_type,
        "index_name": getattr(args, "index_name", ""),
        "args": {}
    }

    # Extract common parameters
    common_params = [
        "force", "verbose", "quiet", "help"
    ]

    for param in common_params:
        if hasattr(args, param):
            config["args"][param] = getattr(args, param)

    # Extract command-specific parameters based on command type
    if command_type == "build":
        # Build command specific parameters
        build_params = [
            "docs_paths", "file_types", "include_hidden", "backend_name",
            "embedding_model", "embedding_mode", "embedding_host", 
            "embedding_api_base", "embedding_api_key", "query_prompt_template",
            "graph_degree", "complexity", "num_threads", "compact", "recompute"
        ]

        for param in build_params:
            if hasattr(args, param):
                config["args"][param] = getattr(args, param)

        # Handle docs_paths as list of Path objects
        if "docs_paths" in config["args"]:
            config["args"]["docs_paths"] = [
                Path(p).resolve() for p in config["args"]["docs_paths"]
            ]

    elif command_type == "search":
        # Search command specific parameters
        search_params = [
            "query", "top_k", "complexity", "beam_width", "prune_ratio",
            "recompute_embeddings", "pruning_strategy", "non_interactive",
            "show_metadata", "embedding_prompt_template"
        ]

        for param in search_params:
            if hasattr(args, param):
                config["args"][param] = getattr(args, param)

    return config

